import java.io.FileInputStream
import java.security.KeyStore
import javax.net.ssl.{HttpsURLConnection, SSLContext, TrustManagerFactory}
import java.net.URL


  try {
    // Load the custom trust store
    val trustStorePath = "/usr/lib/jvm/msopenjdk-11/lib/security/cacerts"
    val trustStorePassword = "changeit"
    val trustStore = KeyStore.getInstance(KeyStore.getDefaultType)
    val trustStoreStream = new FileInputStream(trustStorePath)
    System.setProperty("javax.net.debug", "all");
    try {
      trustStore.load(trustStoreStream, trustStorePassword.toCharArray)
    } finally {
      trustStoreStream.close()
    }

    // Initialize the TrustManagerFactory with the trust store
    val trustManagerFactory = TrustManagerFactory.getInstance(TrustManagerFactory.getDefaultAlgorithm)
    trustManagerFactory.init(trustStore)

    // Create and initialize the SSLContext with the custom trust store
    val sslContext = SSLContext.getInstance("TLS")
    sslContext.init(null, trustManagerFactory.getTrustManagers, new java.security.SecureRandom)

    // Set the default SSL context to use the custom trust store
    HttpsURLConnection.setDefaultSSLSocketFactory(sslContext.getSocketFactory)

    // Now you can make HTTPS requests using the custom trust store
    val url = new URL("https://google.com")
    val connection = url.openConnection().asInstanceOf[HttpsURLConnection]
    connection.connect()

    println(s"Response Code: ${connection.getResponseCode}")

  } catch {
    case e: Exception => e.printStackTrace()
  }

