 val checkIpAddress = udf(() => {
      val executorIp = java.net.InetAddress.getLocalHost.getHostAddress

      // Pattern matching to handle IP check
      executorIp match {
        case "10.0.46.0"  => throw new RuntimeException(s"Blocked IP detected: $executorIp")
        case _ => 
          // Sleep for 1 second if the IP does not match
          Thread.sleep(30000)
          executorIp
      }
    })

    // Create a DataFrame with numbers from 1 to 100
    import spark.implicits._
    val df = Seq(1 to 100: _*).toDF("value")
    val resultDf = df.withColumn("executor_ip", checkIpAddress())
      // Show the results
    resultDf.show(truncate = false)

